import{_ as o,o as e,c as t,a0 as l}from"./chunks/framework.CED9SG98.js";const m=JSON.parse('{"title":"Google 发布 Open Knowledge Format (OKF) — 给 AI Agent 喂知识的标准格式","description":"Google Cloud 团队开源的知识表示格式，基于 markdown + YAML frontmatter，旨在统一 AI 知识库的标准。与 Karpathy 的 llmwiki 理念互补。","frontmatter":{"type":"Source","title":"Google 发布 Open Knowledge Format (OKF) — 给 AI Agent 喂知识的标准格式","description":"Google Cloud 团队开源的知识表示格式，基于 markdown + YAML frontmatter，旨在统一 AI 知识库的标准。与 Karpathy 的 llmwiki 理念互补。","source_url":"https://github.com/GoogleCloudPlatform/knowledge-catalog/tree/main/okf","source_title":"knowledge-catalog/okf at main · GoogleCloudPlatform/knowledge-catalog","source_author":"Google Cloud Platform","source_platform":"网页 (GitHub)","ingest_date":"2026-07-11T00:00:00.000Z","access_date":"2026-07-11T00:00:00.000Z","tags":["AI","知识管理","OKF","标准格式","Google","llmwiki"],"status":"compiled","review_count":0,"last_review":"2026-07-11T00:00:00.000Z","next_review":"2026-07-12T00:00:00.000Z"},"headers":[],"relativePath":"wiki/sources/2026-07-11-google-okf.md","filePath":"wiki/sources/2026-07-11-google-okf.md"}'),n={name:"wiki/sources/2026-07-11-google-okf.md"};function i(r,a,s,d,g,c){return e(),t("div",null,[...a[0]||(a[0]=[l(`<h1 id="google-okf-核心要点" tabindex="-1">Google OKF 核心要点 <a class="header-anchor" href="#google-okf-核心要点" aria-label="Permalink to &quot;Google OKF 核心要点&quot;">​</a></h1><h2 id="_1-是什么" tabindex="-1">1. 是什么 <a class="header-anchor" href="#_1-是什么" aria-label="Permalink to &quot;1. 是什么&quot;">​</a></h2><p>Open Knowledge Format (OKF) 是 Google Cloud 团队开源的<strong>知识表示格式规范</strong>。定义了如何用 markdown 文件 + YAML frontmatter 来组织 AI 可消费的知识库。</p><h2 id="_2-核心设计" tabindex="-1">2. 核心设计 <a class="header-anchor" href="#_2-核心设计" aria-label="Permalink to &quot;2. 核心设计&quot;">​</a></h2><ul><li><strong>最小约束</strong>：只要求 type 字段，其余自由扩展</li><li><strong>人类可读</strong>：任何工程师可以用 <code>cat</code> 阅读</li><li><strong>版本可控</strong>：git 原生支持 diff/blame/review</li><li><strong>无厂商锁定</strong>：目录即 bundle，任意工具可读</li><li><strong>渐进式披露</strong>：index.md 目录 + 层级结构</li></ul><h2 id="_3-文件格式" tabindex="-1">3. 文件格式 <a class="header-anchor" href="#_3-文件格式" aria-label="Permalink to &quot;3. 文件格式&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>path/to/bundle/</span></span>
<span class="line"><span>├── index.md              # 目录索引</span></span>
<span class="line"><span>├── log.md                # 更新日志</span></span>
<span class="line"><span>├── &lt;concept&gt;.md          # 知识单元（YAML frontmatter + markdown body）</span></span>
<span class="line"><span>└── &lt;subdirectory&gt;/</span></span>
<span class="line"><span>    └── ...</span></span></code></pre></div><h2 id="_4-与-llmwiki-的关系" tabindex="-1">4. 与 llmwiki 的关系 <a class="header-anchor" href="#_4-与-llmwiki-的关系" aria-label="Permalink to &quot;4. 与 llmwiki 的关系&quot;">​</a></h2><ul><li>OKF = <strong>存储格式</strong>（怎么存）</li><li>llmwiki = <strong>工作模式</strong>（怎么长）</li><li>两者互补：OKF 提供骨架，llmwiki 提供血肉</li></ul><h2 id="_5-对-eason-的启发" tabindex="-1">5. 对 Eason 的启发 <a class="header-anchor" href="#_5-对-eason-的启发" aria-label="Permalink to &quot;5. 对 Eason 的启发&quot;">​</a></h2><ul><li>用 OKF 规范作为个人知识库的存储标准</li><li>用 llmwiki 的增量编译机制维护知识内容</li><li>结合两者构建完整的 PKMS（Personal Knowledge Management System）</li></ul><h1 id="citations" tabindex="-1">Citations <a class="header-anchor" href="#citations" aria-label="Permalink to &quot;Citations&quot;">​</a></h1><p>[1] <a href="https://github.com/GoogleCloudPlatform/knowledge-catalog/tree/main/okf" target="_blank" rel="noreferrer">https://github.com/GoogleCloudPlatform/knowledge-catalog/tree/main/okf</a> [2] <a href="https://cloud.google.com/blog/products/data-analytics/how-the-open-knowledge-format-can-improve-data-sharing" target="_blank" rel="noreferrer">https://cloud.google.com/blog/products/data-analytics/how-the-open-knowledge-format-can-improve-data-sharing</a></p>`,13)])])}const h=o(n,[["render",i]]);export{m as __pageData,h as default};
